1	/**
2	 * Stage-by-stage checklist of the backend personalization pipeline. Each
3	 * step shows a spinner while active, a check once its corresponding
4	 * `OnboardingStage` lands in `completedStages`, and a 30s "still working"
5	 * notice if everything stalls. Steps differ for the Gmail vs no-Gmail
6	 * branch — the no-Gmail branch is reordered to match actual emit order.
7	 */
8	
9	"use client";
10	
11	import {
12	  Brain01Icon,
13	  CheckListIcon,
14	  CheckmarkCircle02Icon,
15	  FilterIcon,
16	  type IconProps,
17	  Loading03Icon,
18	  Mail01Icon,
19	  ZapIcon,
20	} from "@icons";
21	import { AnimatePresence } from "motion/react";
22	import * as m from "motion/react-m";
23	import { type FC, memo, useEffect, useState } from "react";
24	import {
25	  STEP_BUILDING_PROFILE,
26	  STEP_CREATING_TODOS,
27	  STEP_CREATING_WORKFLOWS,
28	  STEP_LEARNING_STYLE,
29	  STEP_SCANNING_INBOX,
30	  STEP_TRIAGING,
31	} from "../constants/messages";
32	import { EASE_OUT_QUART } from "../constants/motion";
33	import type { OnboardingStage } from "../types/websocket";
34	
35	const SLOW_NOTICE_MS = 30_000;
36	
37	interface ProcessingStep {
38	  icon: FC<IconProps>;
39	  /** The completion stage that flips this step from active → done. */
40	  stage: OnboardingStage;
41	  activeText: string;
42	  /**
43	   * Stages whose `status_text` updates belong to *this* step. Listed in
44	   * priority order — the first slot with a value is shown as the live
45	   * sub-message under the step, so a never-cleared earlier stage cannot
46	   * outrank a fresher later stage in the same group.
47	   */
48	  progressFrom: readonly OnboardingStage[];
49	}
50	
51	const GMAIL_STEPS: ProcessingStep[] = [
52	  {
53	    icon: Mail01Icon,
54	    stage: "inbox_scanning",
55	    activeText: STEP_SCANNING_INBOX,
56	    progressFrom: ["inbox_scanning"],
57	  },
58	  {
59	    icon: Brain01Icon,
60	    stage: "writing_style_ready",
61	    activeText: STEP_LEARNING_STYLE,
62	    progressFrom: ["writing_style_progress"],
63	  },
64	  {
65	    icon: FilterIcon,
66	    stage: "triage_ready",
67	    activeText: STEP_TRIAGING,
68	    progressFrom: ["triage_analyzing"],
69	  },
70	  {
71	    icon: CheckListIcon,
72	    stage: "todos_ready",
73	    activeText: STEP_CREATING_TODOS,
74	    progressFrom: ["todos_creating"],
75	  },
76	  {
77	    icon: ZapIcon,
78	    stage: "workflows_ready",
79	    activeText: STEP_CREATING_WORKFLOWS,
80	    progressFrom: ["workflows_creating"],
81	  },
82	];
83	
84	// Ordered to match the actual backend emission order in the no-Gmail path:
85	// focus-based todos fire first (fast LLM call), then workflows, then the
86	// holo card (phrase + bio + RAG + persist, slowest).
87	const NO_GMAIL_STEPS: ProcessingStep[] = [
88	  {
89	    icon: CheckListIcon,
90	    stage: "todos_ready",
91	    activeText: STEP_CREATING_TODOS,
92	    progressFrom: ["todos_creating"],
93	  },
94	  {
95	    icon: ZapIcon,
96	    stage: "workflows_ready",
97	    activeText: STEP_CREATING_WORKFLOWS,
98	    progressFrom: ["workflows_creating"],
99	  },
100	  {
101	    icon: Brain01Icon,
102	    stage: "holo_ready",
103	    activeText: STEP_BUILDING_PROFILE,
104	    progressFrom: [],
105	  },
106	];
107	
108	interface OnboardingProcessingProps {
109	  hasGmail: boolean;
110	  /** Stages that have received a completion event from the backend */
111	  completedStages?: Set<OnboardingStage>;
112	  /**
113	   * Backend-emitted `status_text` keyed by the stage that emitted it.
114	   * Each step displays only the values for its own `progressFrom` stages,
115	   * so a late progress event from one stage cannot leak into another's
116	   * label.
117	   */
118	  progressByStage?: Partial<Record<OnboardingStage, string>>;
119	}
120	
121	// Stages whose `inbox_scanning` step is genuinely complete. Writing-style
122	// uses an independent 50-sent-email fetch so it firing tells us nothing
123	// about the 500-email inbox scan — exclude it.
124	const STAGES_AFTER_INBOX_SCAN: OnboardingStage[] = [
125	  "triage_ready",
126	  "social_profiles_ready",
127	  "todos_ready",
128	  "workflows_ready",
129	  "complete",
130	];
131	
132	function pickProgressForStep(
133	  step: ProcessingStep,
134	  progressByStage: Partial<Record<OnboardingStage, string>> | undefined,
135	): string | undefined {
136	  if (!progressByStage) return undefined;
137	  for (const stage of step.progressFrom) {
138	    const value = progressByStage[stage];
139	    if (value) return value;
140	  }
141	  return undefined;
142	}
143	
144	function OnboardingProcessingImpl({
145	  hasGmail,
146	  completedStages,
147	  progressByStage,
148	}: OnboardingProcessingProps) {
149	  const steps = hasGmail ? GMAIL_STEPS : NO_GMAIL_STEPS;
150	  const [showSlowNotice, setShowSlowNotice] = useState(false);
151	
152	  // Show "taking longer" notice after 30s
153	  useEffect(() => {
154	    const timer = setTimeout(() => setShowSlowNotice(true), SLOW_NOTICE_MS);
155	    return () => clearTimeout(timer);
156	  }, []);
157	
158	  // Per-step completion: each step is marked done only when ITS own stage
159	  // has fired. `inbox_scanning` is a repeating stage that never emits its
160	  // own completion — it is considered done only when a stage that genuinely
161	  // depends on the inbox fetch has fired (NOT writing_style_ready, which
162	  // uses a separate 50-sent-email fetch and finishes long before the 500-
163	  // email inbox scan).
164	  const isStepDone = (i: number): boolean => {
165	    const step = steps[i];
166	    if (step.stage === "inbox_scanning") {
167	      return STAGES_AFTER_INBOX_SCAN.some((s) => completedStages?.has(s));
168	    }
169	    return completedStages?.has(step.stage) ?? false;
170	  };
171	
172	  const activeStepIndex = (() => {
173	    for (let i = 0; i < steps.length; i++) {
174	      if (!isStepDone(i)) return i;
175	    }
176	    return steps.length - 1;
177	  })();
178	
